+unsafe fn drand48_result_long(data: *const c_void) -> c_long {
+    let x = data as *const u16;
+    let x1 = unsafe { *x.add(1) } as u32;
+    let x2 = unsafe { *x.add(2) } as u32;
+    ((x2 << 16) | x1) as i32 as c_long
